// Cluster + stratified sample.
// Inputs from the form trigger are read via the n8n expression layer.
const FORM = $('Form: Upload CSV + Pick Cluster').first().json;

// Form returns the dropdown label verbatim (e.g. "allergens (2,527)") — strip the count.
const rawCluster = FORM['Hazard category (cluster)'] || '';
const CLUSTER = rawCluster.replace(/\s*\(.*\)\s*$/, '').trim();
const SAMPLE_N = Number(FORM['Sample size']) || 50;
const TOP_K = 10;
const PREFIX_MAP = {
  'allergens': 'alg', 'biological': 'bio', 'foreign bodies': 'fbd',
  'fraud': 'frd', 'chemical': 'chm', 'other hazard': 'oth',
  'packaging defect': 'pkg', 'organoleptic aspects': 'org',
  'food additives and flavourings': 'faf', 'migration': 'mig'
};
const prefix = PREFIX_MAP[CLUSTER] || CLUSTER.slice(0, 3).toLowerCase();

function shuffle(arr) {
  return arr.map(v => [Math.random(), v]).sort((a, b) => a[0] - b[0]).map(p => p[1]);
}

const rows = items.map(it => it.json);
const cluster = rows.filter(r => r['hazard-category'] === CLUSTER);

if (!cluster.length) {
  throw new Error(`No rows found for hazard-category="${CLUSTER}". Check your CSV.`);
}

const counts = {};
for (const r of cluster) counts[r.hazard] = (counts[r.hazard] || 0) + 1;
const topHazards = Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, TOP_K).map(p => p[0]);
const perTop = Math.max(1, Math.floor(SAMPLE_N / topHazards.length));

const seen = new Set();
const sample = [];
for (const h of topHazards) {
  const pool = shuffle(cluster.filter(r => r.hazard === h));
  for (const r of pool.slice(0, perTop)) {
    sample.push(r);
    seen.add(r);
  }
}
const rest = shuffle(cluster.filter(r => !seen.has(r)));
while (sample.length < SAMPLE_N && rest.length) sample.push(rest.shift());

return sample.slice(0, SAMPLE_N).map((r, i) => ({
  json: { ...r, record_id: `${prefix}_${String(i + 1).padStart(3, '0')}` }
}));

