const src = $('Parse Answer').item.json;
const raw = $input.item.json;
const content = raw.message?.content ?? raw.content ?? raw.text ?? raw;
let parsed;
try { parsed = typeof content === 'string' ? JSON.parse(content) : content; }
catch (e) { return { json: { ...src, error: 'judge_parse_failed' } }; }
return { json: {
  record_id: src.record_id,
  hazard_category: src['hazard-category'],
  hazard: src.hazard,
  product_category: src['product-category'],
  product: src.product,
  country: src.country,
  year: src.year,
  title: src.title,
  question: src.question,
  justification: src.justification,
  required_items: JSON.stringify(src.required_items),
  optional_items: JSON.stringify(src.optional_items),
  answer: src.answer,
  required_coverage: parsed.required_coverage ?? 0,
  optional_coverage: parsed.optional_coverage ?? 0,
  overall_score: parsed.overall_score ?? 0,
  verdict: parsed.verdict ?? ''
}};

// Aggregate stats once the loop has finished all batches.
// Pulls the flattened rows that were appended.
const all = $items('Flatten Row').map(it => it.json);
if (!all.length) return [{ json: { summary: 'No rows processed.' } }];

const avg = arr => arr.reduce((a,b)=>a+b,0) / arr.length;
const req = all.map(r => r.required_coverage || 0);
const opt = all.map(r => r.optional_coverage || 0);
const overall = all.map(r => r.overall_score || 0);
const perfectReq = req.filter(x => x >= 1.0).length;
const cluster = all[0]?.hazard_category || 'unknown';

return [{ json: {
  cluster,
  records_processed: all.length,
  avg_required_coverage: +avg(req).toFixed(3),
  avg_optional_coverage: +avg(opt).toFixed(3),
  avg_overall_score: +avg(overall).toFixed(3),
  pct_perfect_required: `${Math.round(100 * perfectReq / all.length)}%`,
}}];
